import { buildPortalView } from "./portal-view.mjs";

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const account = db.accounts.find((item) => item._id === request.accountId);
  const activities = db.activities
    .filter((item) => item.subjectId === request._id)
    .sort((a, b) => a.occurredAt.localeCompare(b.occurredAt));

  // "review by 16:00" deadline pinned to the same UTC day as `now`.
  const dueAt = `${now.slice(0, 10)}T16:00:00.000Z`;

  const evidenceBundle = buildEvidenceBundle(account, activities);

  db.workflow_state.push({
    requestId: request._id,
    accountId: request.accountId,
    title: request.title,
    status: request.expectedOutcome,
    nextStep: request.nextStep,
    riskSignals: request.riskSignals.map((signal) => ({ name: signal.name, detail: signal.detail })),
    evidenceBundle,
    updatedAt: now
  });

  request.ownerGroups.forEach((ownerGroup) => {
    db.owner_tasks.push({
      requestId: request._id,
      accountId: request.accountId,
      ownerGroup,
      title: `${ownerGroup} review: ${request.title}`,
      status: "open",
      dueAt,
      createdAt: now
    });
  });

  db.customer_messages.push({
    requestId: request._id,
    accountId: request.accountId,
    body: request.customerMessage,
    customerSafe: true,
    sentAt: now
  });

  db.audit_events.push({
    requestId: request._id,
    accountId: request.accountId,
    action: "workflow.activated",
    summary: request.expectedOutcome,
    customerVisible: true,
    evidenceCount: evidenceBundle.timeline.length,
    occurredAt: now
  });

  return buildPortalView(db);
}

function buildEvidenceBundle(account, activities) {
  return {
    contract: account?.contract ?? null,
    accountContext: account?.context ?? null,
    timeline: activities.map((item) => ({
      activityId: item._id,
      summary: item.summary,
      occurredAt: item.occurredAt
    }))
  };
}
